ALTER TABLE `sports_day_registrations` MODIFY COLUMN `unlockToken` varchar(36);

-- Generate UUIDs for all existing registrations that don't have one
UPDATE `sports_day_registrations` 
SET `unlockToken` = UUID() 
WHERE `unlockToken` IS NULL OR `unlockToken` = '';

-- Now add the NOT NULL constraint and UNIQUE constraint
ALTER TABLE `sports_day_registrations` MODIFY COLUMN `unlockToken` varchar(36) NOT NULL UNIQUE;

